class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        vector<double> dp(1 << n, 1e9);
        dp[0] = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            for (int i = 0; i < m; i++) {
                for (int j = 1; j <= k && j <= n; j++) {
                    for (int subset = 0; subset < (1 << n); subset++) {
                        if (__builtin_popcount(subset) != j) continue;
                        if ((mask & subset) != subset) continue;
                        double max_time = 0;
                        for (int l = 0; l < n; l++) {
                            if (subset & (1 << l)) {
                                max_time = max(max_time, (double)time[l]);
                            }
                        }
                        double time_taken = max_time * mul[i];
                        int next_mask = mask ^ subset;
                        int next_stage = (i + (int)(time_taken)) % m;
                        dp[next_mask] = min(dp[next_mask], dp[mask] + time_taken);
                        if (next_mask != 0) {
                            double return_time = time[getMinIndex(subset, time)] * mul[next_stage];
                            int return_stage = (next_stage + (int)(return_time)) % m;
                            dp[mask] = min(dp[mask], dp[next_mask] + return_time);
                        }
                    }
                }
            }
        }
        if (dp[(1 << n) - 1] >= 1e9) return -1;
        return dp[(1 << n) - 1];
    }

    int getMinIndex(int subset, vector<int>& time) {
        int min_index = -1;
        int min_val = INT_MAX;
        for (int i = 0; i < time.size(); i++) {
            if (subset & (1 << i)) {
                if (time[i] < min_val) {
                    min_val = time[i];
                    min_index = i;
                }
            }
        }
        return min_index;
    }
};

